import { createTask, getTasks, togglePriority } from "wasp/client/operations";
import "./Main.css";

export function MainPage() {
  const { data: tasks, isLoading, error } = useQuery(getTasks);
  const createTaskFn = useAction(createTask);
  const togglePriorityFn = useAction(togglePriority);
  const [description, setDescription] = useState("");

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    await createTaskFn({ description });
    setDescription("");
  };

  const handleToggle = async (taskId: number) => {
    await togglePriorityFn({ id: taskId });
  };

  return (
    <main className="container">
      <header className="header">
        <h1>Task Priority</h1>
        <p>Track tasks and quickly switch their priority.</p>
      </header>

      <form className="task-form" onSubmit={handleSubmit}>
        <input
          className="task-input"
          type="text"
          placeholder="Add a new task description"
          value={description}
          onChange={(event) => setDescription(event.target.value)}
          required
        />
        <button className="button button-primary" type="submit">
          Add Task
        </button>
      </form>

      {isLoading && <p className="status">Loading tasks...</p>}
      {error && <p className="status error">Error loading tasks.</p>}

      {!isLoading && tasks?.length === 0 && (
        <p className="status">No tasks yet. Add your first task above.</p>
      )}

      <ul className="task-list">
        {tasks?.map((task) => (
          <li key={task.id} className="task-item">
            <div className="task-info">
              <span className="task-desc">{task.description}</span>
              <span
                className={`priority priority-${task.priority.toLowerCase()}`}
              >
                {task.priority}
              </span>
            </div>

