  background: #f5f6fa;
  color: #1f2937;
}

#root {
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: flex-start;
  padding: 4rem 1.5rem;
}

.container {
  width: 100%;
  max-width: 720px;
  background: #ffffff;
  border-radius: 16px;
  padding: 2.5rem;
  box-shadow: 0 20px 40px rgba(15, 23, 42, 0.08);
  display: flex;
  flex-direction: column;
  gap: 2rem;
}

.header h1 {
  font-size: 2.5rem;
  margin-bottom: 0.25rem;
}

.header p {
  color: #6b7280;
}

.task-form {
  display: flex;
  gap: 1rem;
  flex-wrap: wrap;
}

.task-input {
  flex: 1 1 260px;
  padding: 0.75rem 1rem;
  border-radius: 10px;
  border: 1px solid #e5e7eb;
  font-size: 1rem;
}

.task-input:focus {
  outline: none;
  border-color: #6366f1;
  box-shadow: 0 0 0 3px rgba(99, 102, 241, 0.2);
}

.task-list {
  list-style: none;
  display: flex;
  flex-direction: column;
  gap: 1rem;
}

.task-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 1.25rem;
  border-radius: 12px;
  background: #f9fafb;
  border: 1px solid #e5e7eb;
  gap: 1rem;
}

.task-info {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
}

.task-desc {
  font-weight: 600;
}

.priority {
  font-size: 0.85rem;
  font-weight: 600;
  padding: 0.2rem 0.6rem;
  border-radius: 999px;
  width: fit-content;
}

.priority-low {
  background: #e0f2fe;
